-- Import KP Money-Winter-2026.xlsx: all 4 hotels, dedup expenses, add income entries
BEGIN;

-- Create missing properties
DO $p$
DECLARE v_mgr uuid;
BEGIN
  SELECT id INTO v_mgr FROM user_profiles LIMIT 1;
  ON CONFLICT (name) DO NOTHING;
END $p$;

-- Create cash registers for all properties that don't have one
SELECT p.id, 'Каса '||p.name, 0, '2025-01-01'
FROM properties p
WHERE NOT EXISTS (SELECT 1 FROM property_cash_registers pcr WHERE pcr.property_id=p.id);

DO $mig$
DECLARE
  v_user uuid; v_acc uuid;
  v_riv uuid; v_rva uuid; v_cin uuid; v_fr uuid; v_kp uuid; v_loz uuid;
  d_riv uuid; d_rva uuid; d_cin uuid; d_fr uuid; d_kp uuid; d_loz uuid;
BEGIN
  SELECT id INTO v_user FROM user_profiles LIMIT 1;
  SELECT id INTO v_acc FROM usali_accounts WHERE code='8601' LIMIT 1;
  IF v_acc IS NULL THEN SELECT id INTO v_acc FROM usali_accounts ORDER BY code LIMIT 1; END IF;

  SELECT id INTO v_riv FROM properties WHERE name='Ривърсайд';
  SELECT id INTO v_rva FROM properties WHERE name='Ривърсайд Анекс';
  SELECT id INTO v_cin FROM properties WHERE name='Cinema';
  SELECT id INTO v_fr FROM properties WHERE name='Френдс';
  SELECT id INTO v_kp FROM properties WHERE name='КП Хотелс';
  SELECT id INTO v_loz FROM properties WHERE name='Лозенец Резорт';

  -- Ensure 'Общо' department exists for each
  SELECT p_id, 'Общо', v_user, 'ACTIVE', 'EXPENSE'
  FROM (VALUES (v_riv),(v_rva),(v_cin),(v_fr),(v_kp),(v_loz)) t(p_id)
  WHERE p_id IS NOT NULL
  ON CONFLICT (property_id, name) DO NOTHING;

  SELECT id INTO d_riv FROM departments WHERE property_id=v_riv AND name='Общо';
  SELECT id INTO d_rva FROM departments WHERE property_id=v_rva AND name='Общо';
  SELECT id INTO d_cin FROM departments WHERE property_id=v_cin AND name='Общо';
  SELECT id INTO d_fr  FROM departments WHERE property_id=v_fr  AND name='Общо';
  SELECT id INTO d_kp  FROM departments WHERE property_id=v_kp  AND name='Общо';
  SELECT id INTO d_loz FROM departments WHERE property_id=v_loz AND name='Общо';

  CREATE TEMP TABLE stg_exp (hotel text, supplier text, inv text, issue_date date, due_date date, amt numeric, paid_at date, paid_from text, status text, method text) ON COMMIT DROP;

ресторантьори','членски внос за 2025','2025-11-14','2025-11-14',184.07,'2025-11-14','Уникредит Лева','PAID','BANK_TRANSFER');

  -- Upsert suppliers from staging
  SELECT DISTINCT s.supplier, true FROM stg_exp s
  WHERE s.supplier IS NOT NULL AND s.supplier <> ''
  ON CONFLICT DO NOTHING;

  SELECT
    CASE s.hotel
      WHEN 'Ривърсайд' THEN v_riv
      WHEN ' Ривърсайд Анекс' THEN v_rva
      WHEN 'Ривърсайд Анекс' THEN v_rva
      WHEN 'Синема' THEN v_cin
      WHEN 'Френдс' THEN v_fr
      WHEN 'КП Хотелс' THEN v_kp
      WHEN 'Лозенец Резорт' THEN v_loz
    END,
    CASE s.hotel
      WHEN 'Ривърсайд' THEN d_riv
      WHEN ' Ривърсайд Анекс' THEN d_rva
      WHEN 'Ривърсайд Анекс' THEN d_rva
      WHEN 'Синема' THEN d_cin
      WHEN 'Френдс' THEN d_fr
      WHEN 'КП Хотелс' THEN d_kp
      WHEN 'Лозенец Резорт' THEN d_loz
    END,
    s.supplier,
    (SELECT id FROM suppliers WHERE name=s.supplier LIMIT 1),
    CASE WHEN s.inv ~ '^[0-9]' THEN 'INVOICE' ELSE 'RECEIPT' END,
    s.inv, s.issue_date, s.due_date, s.amt, 0, s.method, s.paid_at, s.paid_from, s.status, v_acc, v_user
  FROM stg_exp s
  WHERE NOT EXISTS (
    SELECT 1 FROM expenses e
    WHERE e.issue_date = s.issue_date
      AND (
        (s.inv IS NOT NULL AND e.document_number = s.inv)
        OR (s.inv IS NULL AND e.supplier = s.supplier AND ABS(e.amount_net - s.amt) < 0.01)
      )
  );

  CREATE TEMP TABLE stg_inc (hotel text, d date, amt numeric, kasa text, vid text, descr text) ON COMMIT DROP;


  SELECT s.d,
    CASE s.hotel
      WHEN 'Ривърсайд' THEN v_riv
      WHEN ' Ривърсайд Анекс' THEN v_rva
      WHEN 'Ривърсайд Анекс' THEN v_rva
      WHEN 'Синема' THEN v_cin
      WHEN 'Френдс' THEN v_fr
      WHEN 'КП Хотелс' THEN v_kp
      WHEN 'Лозенец Резорт' THEN v_loz
    END,
    CASE WHEN s.vid = 'в брой' THEN 'INC_CASH' ELSE 'INC_BANK' END,
    s.amt,
    CASE WHEN s.vid = 'в брой' THEN 'CASH' ELSE 'BANK' END,
    COALESCE(s.kasa, 'n/a'),
    s.descr,
    v_user, v_acc
  FROM stg_inc s
  WHERE NOT EXISTS (
    SELECT 1 FROM income_entries ie
    WHERE ie.entry_date = s.d
      AND ABS(ie.amount - s.amt) < 0.01
      AND COALESCE(ie.description,'') = COALESCE(s.descr,'')
  );
END $mig$;

COMMIT;
